public enum TransactionType {
    DEPOSIT,
    WITHDRAWAL,
    TRANSFER_OUT,
    TRANSFER_IN
}package com.example.bankapp.repository;

import com.example.bankapp.data.Account;
import com.example.bankapp.data.Transaction;
import com.example.bankapp.data.TransactionType;

import java.util.ArrayList;
import java.util.List;
import java.util.UUID;

public class BankingRepository {

    private static BankingRepository instance;
    private Account currentAccount;
    private List<Transaction> transactionHistory;

    private BankingRepository() {
        // Simulate a logged-in account
        currentAccount = new Account("1234567890", "John Doe", 1500.00);
        transactionHistory = new ArrayList<>();
        // Add some initial transactions
        transactionHistory.add(new Transaction(UUID.randomUUID().toString(), currentAccount.getAccountNumber(), TransactionType.DEPOSIT, 1000.00, "Initial Deposit", 1000.00));
        transactionHistory.add(new Transaction(UUID.randomUUID().toString(), currentAccount.getAccountNumber(), TransactionType.DEPOSIT, 500.00, "Salary", 1500.00));
    }

    public static synchronized BankingRepository getInstance() {
        if (instance == null) {
            instance = new BankingRepository();
        }
        return instance;
    }

    public Account getAccount() {
        // In a real app, this would fetch from a remote server/local DB
        return currentAccount;
    }

    public List<Transaction> getTransactionHistory() {
        // In a real app, this would fetch from a remote server/local DB
        return new ArrayList<>(transactionHistory); // Return a copy to prevent external modification
    }

    // --- Transaction Processing ---

    public boolean deposit(double amount, String description) {
        if (amount <= 0) {
            return false;
        }
        currentAccount.deposit(amount);
        Transaction transaction = new Transaction(
                UUID.randomUUID().toString(),
                currentAccount.getAccountNumber(),
                TransactionType.DEPOSIT,
                amount,
                description,
                currentAccount.getBalance()
        );
        transactionHistory.add(transaction);
        return true;
    }

    public boolean withdraw(double amount, String description) {
        if (amount <= 0 || amount > currentAccount.getBalance()) {
            return false;
        }
        if (currentAccount.withdraw(amount)) {
            Transaction transaction = new Transaction(
                    UUID.randomUUID().toString(),
                    currentAccount.getAccountNumber(),
                    TransactionType.WITHDRAWAL,
                    amount,
                    description,
                    currentAccount.getBalance()
            );
            transactionHistory.add(transaction);
            return true;
        }
        return false;
    }
}package com.example.bankapp.viewmodel;

import androidx.lifecycle.LiveData;
import androidx.lifecycle.MutableLiveData;
import androidx.lifecycle.ViewModel;

import com.example.bankapp.data.Account;
import com.example.bankapp.data.Transaction;
import com.example.bankapp.repository.BankingRepository;

import java.util.List;

public class BankingViewModel extends ViewModel {

    private BankingRepository repository;

    private MutableLiveData<Account> _account = new MutableLiveData<>();
    public LiveData<Account> account = _account;

    private MutableLiveData<List<Transaction>> _transactions = new MutableLiveData<>();
    public LiveData<List<Transaction>> transactions = _transactions;

    private MutableLiveData<String> _errorMessage = new MutableLiveData<>();
    public LiveData<String> errorMessage = _errorMessage;

    private MutableLiveData<Boolean> _transactionSuccess = new MutableLiveData<>();
    public LiveData<Boolean> transactionSuccess = _transactionSuccess;

    public BankingViewModel() {
        repository = BankingRepository.getInstance();
        loadAccountData();
        loadTransactionHistory();
    }

    public void loadAccountData() {
        Account fetchedAccount = repository.getAccount();
        _account.postValue(fetchedAccount);
    }

    public void loadTransactionHistory() {
        List<Transaction> history = repository.getTransactionHistory();
        _transactions.postValue(history);
    }

    public void deposit(double amount, String description) {
        if (amount <= 0) {
            _errorMessage.postValue("Deposit amount must be positive.");
            _transactionSuccess.postValue(false);
            return;
        }
        boolean success = repository.deposit(amount, description);
        if (success) {
            loadAccountData(); // Update balance
            loadTransactionHistory(); // Update transactions
            _transactionSuccess.postValue(true);
        } else {
            _errorMessage.postValue("Deposit failed. Please try again.");
            _transactionSuccess.postValue(false);
        }
    }

    public void withdraw(double amount, String description) {
        if (amount <= 0) {
            _errorMessage.postValue("Withdrawal amount must be positive.");
            _transactionSuccess.postValue(false);
            return;
        }
        if (amount > repository.getAccount().getBalance()) {
            _errorMessage.postValue("Insufficient funds.");
            _transactionSuccess.postValue(false);
            return;
        }
        boolean success = repository.withdraw(amount, description);
        if (success) {
            loadAccountData(); // Update balance
            loadTransactionHistory(); // Update transactions
            _transactionSuccess.postValue(true);
        } else {
            _errorMessage.postValue("Withdrawal failed. Please try again.");
            _transactionSuccess.postValue(false);
        }
    }

    // Reset transaction success state after it's observed
    public void resetTransactionState() {
        _transactionSuccess.postValue(null);
        _errorMessage.postValue(null);
    }
}package com.example.bankapp.ui;

import android.os.Bundle;
import android.view.View;
import android.widget.ArrayAdapter;
import android.widget.Button;
import android.widget.EditText;
import android.widget.ListView;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;
import androidx.lifecycle.ViewModelProvider;

import com.example.bankapp.R; // Assumes R class exists, meaning a project structure
import com.example.bankapp.data.Transaction;
import com.example.bankapp.viewmodel.BankingViewModel;

import java.util.ArrayList;
import java.util.List;
import java.util.Locale;

public class BankingActivity extends AppCompatActivity {

    private BankingViewModel viewModel;

    private TextView accountHolderNameTextView;
    private TextView accountNumberTextView;
    private TextView balanceTextView;
    private EditText amountEditText;
    private EditText descriptionEditText;
    private Button depositButton;
    private Button withdrawButton;
    private ListView transactionsListView;

    private ArrayAdapter<String> transactionsAdapter;
    private List<String> transactionStringList;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_banking);

        accountHolderNameTextView = findViewById(R.id.accountHolderNameTextView);
        accountNumberTextView = findViewById(R.id.accountNumberTextView);
        balanceTextView = findViewById(R.id.balanceTextView);
        amountEditText = findViewById(R.id.amountEditText);
        descriptionEditText = findViewById(R.id.descriptionEditText);
        depositButton = findViewById(R.id.depositButton);
        withdrawButton = findViewById(R.id.withdrawButton);
        transactionsListView = findViewById(R.id.transactionsListView);

        transactionStringList = new ArrayList<>();
        transactionsAdapter = new ArrayAdapter<>(this, android.R.layout.simple_list_item_1, transactionStringList);
        transactionsListView.setAdapter(transactionsAdapter);

        viewModel = new ViewModelProvider(this).get(BankingViewModel.class);

        // Observe account data (balance, holder name, etc.)
        viewModel.account.observe(this, account -> {
            if (account != null) {
                accountHolderNameTextView.setText(account.getAccountHolderName());
                accountNumberTextView.setText(account.getAccountNumber());
                balanceTextView.setText(String.format(Locale.getDefault(), "Balance: $%.2f", account.getBalance()));
            }
        });

        // Observe transaction history
        viewModel.transactions.observe(this, transactions -> {
            transactionStringList.clear();
            if (transactions != null) {
                for (Transaction transaction : transactions) {
                    transactionStringList.add(transaction.toString());
                }
            }
            transactionsAdapter.notifyDataSetChanged();
        });

        // Observe transaction success/failure
        viewModel.transactionSuccess.observe(this, isSuccess -> {
            if (isSuccess != null) {
                if (isSuccess) {
                    Toast.makeText(BankingActivity.this, "Transaction successful!", Toast.LENGTH_SHORT).show();
                    amountEditText.setText("");
                    descriptionEditText.setText("");
                } else {
                    // Error message will be handled by errorMessage observer
                }
                viewModel.resetTransactionState(); // Reset state to avoid re-triggering on rotation etc.
            }
        });

        // Observe error messages
        viewModel.errorMessage.observe(this, errorMessage -> {
            if (errorMessage != null && !errorMessage.isEmpty()) {
                Toast.makeText(BankingActivity.this, errorMessage, Toast.LENGTH_LONG).show();
                viewModel.resetTransactionState(); // Reset state
            }
        });


        depositButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                processTransaction(true); // true for deposit
            }
        });

        withdrawButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                processTransaction(false); // false for withdrawal
            }
        });
    }

    private void processTransaction(boolean isDeposit) {
        String amountStr = amountEditText.getText().toString();
        String description = descriptionEditText.getText().toString();

        if (amountStr.isEmpty()) {
            Toast.makeText(this, "Please enter an amount.", Toast.LENGTH_SHORT).show();
            return;
        }

        double amount;
        try {
            amount = Double.parseDouble(amountStr);
        } catch (NumberFormatException e) {
            Toast.makeText(this, "Invalid amount format.", Toast.LENGTH_SHORT).show();
            return;
        }

        if (isDeposit) {
            viewModel.deposit(amount, description.isEmpty() ? "Deposit" : description);
        } else {
            viewModel.withdraw(amount, description.isEmpty() ? "Withdrawal" : description);
        }
    }
}